import { useNavigate } from "react-router-dom";
import StarRating from "./Rating/StarRatingByUser";
import TagCard from "./TagCard";

function CourseCard({ courseInfo = {} }) {
  const navigate = useNavigate();
  const ratingColor = "#f7c41cff";

  return (
    <article className="course-card" onClick={() => navigate("/course/" + courseInfo.Id)}>
      <div className="course-card-media">
        <img src={courseInfo.image || "/Files/placeholder.png"} alt={courseInfo?.Title || "Course image"} />
      </div>

      <div className="course-card-content">
        <h3 className="course-card-title">{courseInfo?.Title}</h3>
        <p className="course-card-desc">{courseInfo?.Description}</p>

        <ul className="tag-list">
          {courseInfo?.tags?.map((item, index) => (
            <li className="tag-list-item" key={index}>
              <TagCard Text={item} />
            </li>
          ))}
        </ul>

        <div className="course-card-footer">
          <div className="rating-row">
            <span className="rating-value" style={{ color: ratingColor }}>{courseInfo?.Rating ?? 0}</span>
            <StarRating rating={courseInfo?.Rating} SizeStar={16} Clr={ratingColor} />
          </div>
        </div>

        <div className="price-badge">
          <span>{courseInfo?.Price === 0 ? "бесплатно" : courseInfo?.Price}</span>
        </div>
      </div>
    </article>
  );
}

export default CourseCard;
